@* Channel list sidebar *@

<div class="channel-list">
    <h2 class="channel-list-header">Channels</h2>

    @foreach (var channel in Channels)
    {
        <button class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
            <div class="channel-name-row">
                <span class="channel-name"># @channel.Name</span>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </div>
            @if (!string.IsNullOrWhiteSpace(channel.Description))
            {
                <span class="channel-desc">@Truncate(channel.Description, 40)</span>
            }
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int SelectedChannelId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-list {
    height: 100%;
    overflow-y: auto;
    padding: 12px 0;
    background: var(--sidebar-bg, #3f0e40);
    color: var(--sidebar-text, #cfc3cf);
}

.channel-list-header {
    font-size: 1rem;
    font-weight: 700;
    padding: 8px 16px 12px;
    color: var(--sidebar-header, #fff);
    margin: 0;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    background: none;
    border: none;
    padding: 6px 16px;
    cursor: pointer;
    color: inherit;
    border-radius: 0 6px 6px 0;
    margin-right: 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: var(--sidebar-active-bg, #1164a3);
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-size: 0.9rem;
    font-weight: 500;
}

.unread-badge {
    background: var(--badge-bg, #e01e5a);
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    display: block;
    font-size: 0.75rem;
    opacity: 0.7;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@* Main message area with header, scrollable messages, and input *@

<div class="message-area">
    <div class="message-area-header">
        <h2 class="channel-title"># @ChannelName</h2>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="channel-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
        @if (_isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea"
                  @bind="_newMessageContent"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Message #@ChannelName"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(_newMessageContent)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ChannelName { get; set; } = "";

    [Parameter]
    public string? ChannelDescription { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private string _newMessageContent = "";
    private bool _isLoadingMore;
    private ElementReference _messageListRef;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers load more (handled via JS interop in production;
        // here we use the event as a signal)
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(_newMessageContent)) return;

        var content = _newMessageContent;
        _newMessageContent = "";
        await OnSendMessage.InvokeAsync(content);
    }

    public async Task TriggerLoadMore()
    {
        if (_isLoadingMore) return;
        _isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        _isLoadingMore = false;
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bg-main, #fff);
}

.message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.channel-title {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: var(--text-primary, #1d1c1d);
}

.channel-description {
    font-size: 0.8rem;
    color: var(--text-muted, #616061);
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: var(--text-muted, #616061);
}

.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid var(--border-color, #ddd);
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    min-height: 40px;
    max-height: 120px;
    outline: none;
    transition: border-color 0.2s;
}

.message-textarea:focus {
    border-color: var(--focus-border, #1264a3);
}

.send-btn {
    padding: 10px 20px;
    background: var(--btn-primary, #007a5a);
    color: #fff;
    border: none;
    border-radius: 8px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s;
}

.send-btn:hover:not(:disabled) {
    opacity: 0.9;
}

.send-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

@* Thread panel — shows original message + replies *@

<div class="thread-panel">
    <div class="thread-header">
        <h3 class="thread-title">Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="thread-root-author">@RootMessage.Author</span>
            <p class="thread-root-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="thread-input-area">
            <textarea class="thread-textarea"
                      @bind="_replyContent"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply…"
                      rows="1"></textarea>
            <button class="reply-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(_replyContent)">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message? RootMessage { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Replies { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback OnClose { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendReply { get; set; }

    private string _replyContent = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(_replyContent)) return;

        var content = _replyContent;
        _replyContent = "";
        await OnSendReply.InvokeAsync(content);
    }

    private static string FormatRelativeTime(DateTime time)
    {
        var diff = DateTime.Now - time;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return time.ToString("MMM d, yyyy");
    }
}

