toolArgs.file_text:
@* Channel list sidebar *@

<div class="channel-list">
    <h2 class="channel-list-header">Channels</h2>

    @foreach (var channel in Channels)
    {
        <button class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
            <div class="channel-name-row">
                <span class="channel-name"># @channel.Name</span>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </div>
            @if (!string.IsNullOrWhiteSpace(channel.Description))
            {
                <span class="channel-desc">@Truncate(channel.Description, 40)</span>
            }
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int SelectedChannelId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@* Main message area with header, scrollable messages, and input *@

<div class="message-area">
    <div class="message-area-header">
        <h2 class="channel-title"># @ChannelName</h2>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="channel-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
        @if (_isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea"
                  @bind="_newMessageContent"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Message #@ChannelName"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(_newMessageContent)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ChannelName { get; set; } = "";

    [Parameter]
    public string? ChannelDescription { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private string _newMessageContent = "";
    private bool _isLoadingMore;
    private ElementReference _messageListRef;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers load more (handled via JS interop in production;
        // here we use the event as a signal)
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(_newMessageContent)) return;

        var content = _newMessageContent;
        _newMessageContent = "";
        await OnSendMessage.InvokeAsync(content);
    }

    public async Task TriggerLoadMore()
    {
        if (_isLoadingMore) return;
        _isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        _isLoadingMore = false;
    }
}

