.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bg-main, #fff);
}

.message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.channel-title {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: var(--text-primary, #1d1c1d);
}

.channel-description {
    font-size: 0.8rem;
    color: var(--text-muted, #616061);
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: var(--text-muted, #616061);
}

.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid var(--border-color, #ddd);
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    min-height: 40px;
    max-height: 120px;
    outline: none;
    transition: border-color 0.2s;
}

.message-textarea:focus {
    border-color: var(--focus-border, #1264a3);
}

.send-btn {
    padding: 10px 20px;
    background: var(--btn-primary, #007a5a);
    color: #fff;
    border: none;
    border-radius: 8px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s;
}

.send-btn:hover:not(:disabled) {
    opacity: 0.9;
}

.send-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

