toolArgs.file_text:
@* Thread panel — shows original message + replies *@

<div class="thread-panel">
    <div class="thread-header">
        <h3 class="thread-title">Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="thread-root-author">@RootMessage.Author</span>
            <p class="thread-root-content">@RootMessage.Content</p>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="thread-input-area">
            <textarea class="thread-textarea"
                      @bind="_replyContent"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply…"
                      rows="1"></textarea>
            <button class="reply-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(_replyContent)">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message? RootMessage { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Replies { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback OnClose { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendReply { get; set; }

    private string _replyContent = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(_replyContent)) return;

        var content = _replyContent;
        _replyContent = "";
        await OnSendReply.InvokeAsync(content);
    }

    private static string FormatRelativeTime(DateTime time)
    {
        var diff = DateTime.Now - time;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return time.ToString("MMM d, yyyy");
    }
}

