.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: var(--bg-main, #fff);
    border-left: 1px solid var(--border-color, #e0e0e0);
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.thread-title {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    color: var(--text-muted, #616061);
}

.close-btn:hover {
    background: var(--hover-bg, #f0f0f0);
}

.thread-root-message {
    padding: 12px 16px;
    background: var(--highlight-bg, #f8f8f8);
    border-bottom: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.thread-root-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.thread-root-content {
    margin: 4px 0 0;
    font-size: 0.85rem;
    line-height: 1.4;
    color: var(--text-primary, #1d1c1d);
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: var(--text-muted, #616061);
    border-bottom: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 6px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: var(--text-muted, #616061);
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
    margin-top: 2px;
}

.thread-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid var(--border-color, #e0e0e0);
    flex-shrink: 0;
}

.thread-textarea {
    flex: 1;
    resize: none;
    border: 1px solid var(--border-color, #ddd);
    border-radius: 8px;
    padding: 8px 10px;
    font-size: 0.85rem;
    font-family: inherit;
    min-height: 36px;
    max-height: 100px;
    outline: none;
}

.thread-textarea:focus {
    border-color: var(--focus-border, #1264a3);
}

.reply-btn {
    padding: 8px 16px;
    background: var(--btn-primary, #007a5a);
    color: #fff;
    border: none;
    border-radius: 8px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
}

.reply-btn:hover:not(:disabled) {
    opacity: 0.9;
}

.reply-btn:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

