+    private const int PageSize = 30;
+    private int _messagesLoaded;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _channels = await ChatService.GetChannelsAsync();
+
+        if (_channels.Count > 0)
+        {
+            await SelectChannel(_channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        _selectedChannelId = channelId;
+        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
+        _messagesLoaded = 0;
+        _messages = [];
+        _threadSummaries = [];
+
+        CloseThread();
+
+        if (_selectedChannel is not null)
+        {
+            _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+            _messagesLoaded = _messages.Count;
+            BuildThreadSummaries();
+            await ChatService.MarkChannelReadAsync(channelId);
+
+            // Update unread count locally
+            var idx = _channels.FindIndex(c => c.Id == channelId);
+            if (idx >= 0)
+            {
+                _channels[idx] = _channels[idx] with { UnreadCount = 0 };
+            }
+        }
+    }
+
+    private async Task LoadMoreMessages()
+    {
+        if (_selectedChannel is null) return;
+
+        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _messagesLoaded, PageSize);
+        if (older.Count > 0)
+        {
+            _messages.InsertRange(0, older);
+            _messagesLoaded += older.Count;
+            BuildThreadSummaries();
+        }
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (_selectedChannel is null) return;
+
+        var message = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
+        _messages.Add(message);
+        _messagesLoaded++;
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistic update: add reaction locally
+        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
+        if (msg is not null)
+        {
+            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
+            if (existing is not null)
+            {
+                existing.Users.Add("You");
+            }
+            else
+            {
+                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
+            }
+        }
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
+        if (_threadRootMessage is null) return;
+
+        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        _threadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        _threadOpen = false;
+        _threadRootMessage = null;
+        _threadReplies = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (_threadRootMessage is null || _selectedChannel is null) return;
+
+        var reply = await ChatService.SendMessageAsync(_selectedChannel.Id, content, _threadRootMessage.Id);
+        _threadReplies.Add(reply);
+
+        // Update thread summary
+        var summary = _threadSummaries.FirstOrDefault(t => t.RootMessageId == _threadRootMessage.Id);
+        if (summary is not null)
+        {
+            var idx = _threadSummaries.IndexOf(summary);
+            _threadSummaries[idx] = new ThreadSummary(_threadRootMessage.Id, summary.ReplyCount + 1, DateTime.Now);
+        }
+        else
+        {
+            _threadSummaries.Add(new ThreadSummary(_threadRootMessage.Id, 1, DateTime.Now));
+        }
+    }
+
+    private void BuildThreadSummaries()
+    {
+        // Build thread summaries from messages that have replies
+        var repliedToIds = _messages
+            .Where(m => m.ReplyToId.HasValue)
+            .GroupBy(m => m.ReplyToId!.Value)
+            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
+            .ToList();
+
+        _threadSummaries = repliedToIds;
+    }
+}
